use enigo::{Enigo, Mouse, Settings};
use rand::Rng;
use std::thread;
use std::time::Duration;

fn rng() -> impl Rng {
    rand::thread_rng()
}

#[derive(Debug, Clone, Copy)]
pub struct Point {
    pub x: f64,
    pub y: f64,
}

impl Point {
    pub fn new(x: f64, y: f64) -> Self {
        Self { x, y }
    }
}

pub struct HumanMouse {
    enigo: Enigo,
}

impl HumanMouse {
    pub fn new() -> Result<Self, String> {
        let enigo = Enigo::new(&Settings::default()).map_err(|e| e.to_string())?;
        Ok(Self { enigo })
    }

    pub fn get_position(&self) -> Result<Point, String> {
        let (x, y) = self.enigo.location().map_err(|e| e.to_string())?;
        Ok(Point::new(x as f64, y as f64))
    }

    pub fn move_to(&mut self, x: i32, y: i32) -> Result<(), String> {
        self.enigo
            .move_mouse(x, y, enigo::Coordinate::Abs)
            .map_err(|e| e.to_string())
    }

    pub fn human_move(&mut self, human_like: bool) -> Result<(), String> {
        let start = self.get_position()?;
        let mut rng = rng();

        // Random distance: 5-50 pixels
        let distance: f64 = rng.gen_range(5.0..50.0);
        let angle: f64 = rng.gen_range(0.0..std::f64::consts::TAU);

        let end = Point::new(
            start.x + distance * angle.cos(),
            start.y + distance * angle.sin(),
        );

        if human_like {
            self.bezier_move(start, end)?;
        } else {
            self.move_to(end.x as i32, end.y as i32)?;
        }

        // Small delay before returning
        let return_delay = rng.gen_range(50..150);
        thread::sleep(Duration::from_millis(return_delay));

        // Return to original position (also with human-like movement)
        if human_like {
            self.bezier_move(end, start)?;
        } else {
            self.move_to(start.x as i32, start.y as i32)?;
        }

        Ok(())
    }

    fn bezier_move(&mut self, start: Point, end: Point) -> Result<(), String> {
        let mut rng = rng();

        // Generate control points for cubic Bézier curve
        let mid_x = (start.x + end.x) / 2.0;
        let mid_y = (start.y + end.y) / 2.0;
        let deviation = 30.0;

        let ctrl1 = Point::new(
            mid_x + rng.gen_range(-deviation..deviation),
            mid_y + rng.gen_range(-deviation..deviation),
        );
        let ctrl2 = Point::new(
            mid_x + rng.gen_range(-deviation..deviation),
            mid_y + rng.gen_range(-deviation..deviation),
        );

        // Number of steps (more steps = smoother movement)
        let steps: u32 = rng.gen_range(25..40);
        let step_delay = rng.gen_range(5..15);

        for i in 0..=steps {
            let t = i as f64 / steps as f64;

            // Apply easing (ease-in-out)
            let t_eased = ease_in_out(t);

            let point = cubic_bezier(t_eased, start, ctrl1, ctrl2, end);

            // Add micro-tremor (Gaussian-like noise)
            let tremor_x = rng.gen_range(-0.5..0.5);
            let tremor_y = rng.gen_range(-0.5..0.5);

            self.move_to(
                (point.x + tremor_x) as i32,
                (point.y + tremor_y) as i32,
            )?;

            thread::sleep(Duration::from_millis(step_delay));
        }

        // Occasional overshoot (10% chance)
        if rng.gen_bool(0.1) {
            let overshoot = rng.gen_range(2.0..5.0);
            let overshoot_point = Point::new(
                end.x + overshoot * (end.x - start.x).signum(),
                end.y + overshoot * (end.y - start.y).signum(),
            );
            self.move_to(overshoot_point.x as i32, overshoot_point.y as i32)?;
            thread::sleep(Duration::from_millis(30));
            self.move_to(end.x as i32, end.y as i32)?;
        }

        Ok(())
    }
}

fn cubic_bezier(t: f64, p0: Point, p1: Point, p2: Point, p3: Point) -> Point {
    let u = 1.0 - t;
    let tt = t * t;
    let uu = u * u;
    let uuu = uu * u;
    let ttt = tt * t;

    Point {
        x: uuu * p0.x + 3.0 * uu * t * p1.x + 3.0 * u * tt * p2.x + ttt * p3.x,
        y: uuu * p0.y + 3.0 * uu * t * p1.y + 3.0 * u * tt * p2.y + ttt * p3.y,
    }
}

fn ease_in_out(t: f64) -> f64 {
    if t < 0.5 {
        2.0 * t * t
    } else {
        1.0 - (-2.0 * t + 2.0).powi(2) / 2.0
    }
}

