mod presence;
mod tray;

use config::Config;
use presence::PresenceKeeper;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Mutex;
use tauri::{Manager, RunEvent, WindowEvent};

static SHOULD_EXIT: AtomicBool = AtomicBool::new(false);

pub fn request_exit() {
    SHOULD_EXIT.store(true, Ordering::SeqCst);
}

#[cfg(target_os = "macos")]
use tauri::ActivationPolicy;

pub struct AppState {
    pub keeper: Mutex<PresenceKeeper>,
    pub config: Mutex<Config>,
}

#[tauri::command]
fn get_config(state: tauri::State<AppState>) -> Config {
    state.config.lock().unwrap().clone()
}

#[tauri::command]
fn save_config(state: tauri::State<AppState>, config: Config) -> Result<(), String> {
    config.save()?;

    // Update running keeper with new config
    let mut keeper = state.keeper.lock().unwrap();
    keeper.update_config(config.clone());

    // Update stored config
    let mut stored_config = state.config.lock().unwrap();
    *stored_config = config;

    Ok(())
}

#[tauri::command]
fn toggle_enabled(state: tauri::State<AppState>) -> bool {
    let mut keeper = state.keeper.lock().unwrap();
    if keeper.is_running() {
        keeper.stop();
        false
    } else {
        keeper.start();
        true
    }
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    let config = Config::load();
    let keeper = PresenceKeeper::new(config.clone());

    tauri::Builder::default()
        .plugin(tauri_plugin_shell::init())
        .manage(AppState {
            keeper: Mutex::new(keeper),
            config: Mutex::new(config),
        })
        .invoke_handler(tauri::generate_handler![get_config, save_config, toggle_enabled])
        .setup(|app| {
            // Hide dock icon on macOS (tray-only app)
            #[cfg(target_os = "macos")]
            app.set_activation_policy(ActivationPolicy::Accessory);

            // Create system tray
            tray::create_tray(app.handle())?;

            // Auto-start the keeper if enabled
            let state = app.state::<AppState>();
            let config = state.config.lock().unwrap();
            if config.enabled {
                let mut keeper = state.keeper.lock().unwrap();
                keeper.start();
            }

            // Hide the main window on startup (tray-only app)
            if let Some(window) = app.get_webview_window("main") {
                let _ = window.hide();
            }

            Ok(())
        })
        .build(tauri::generate_context!())
        .expect("error while building tauri application")
        .run(|app_handle, event| {
            match event {
                RunEvent::WindowEvent {
                    label,
                    event: WindowEvent::CloseRequested { api, .. },
                    ..
                } => {
                    // Prevent the window from being destroyed, just hide it
                    api.prevent_close();
                    if let Some(window) = app_handle.get_webview_window(&label) {
                        let _ = window.hide();
                    }
                }
                RunEvent::ExitRequested { api, .. } => {
                    // Only prevent exit if we don't want to quit
                    if !SHOULD_EXIT.load(Ordering::SeqCst) {
                        api.prevent_exit();
                    }
                }
                _ => {}
            }
        });
}

