use crate::config::Config;
use crate::mouse::HumanMouse;
use enigo::{Enigo, Key, Keyboard, Settings};
use rand::Rng;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, Instant};

fn rng() -> impl Rng {
    rand::thread_rng()
}

pub struct PresenceKeeper {
    config: Config,
    running: Arc<AtomicBool>,
    paused_until: Arc<Mutex<Option<Instant>>>,
}

impl PresenceKeeper {
    pub fn new(config: Config) -> Self {
        Self {
            config,
            running: Arc::new(AtomicBool::new(false)),
            paused_until: Arc::new(Mutex::new(None)),
        }
    }

    pub fn update_config(&mut self, config: Config) {
        self.config = config;
    }

    pub fn is_running(&self) -> bool {
        self.running.load(Ordering::SeqCst)
    }

    pub fn start(&mut self) {
        if self.running.load(Ordering::SeqCst) {
            return;
        }

        self.running.store(true, Ordering::SeqCst);
        let running = self.running.clone();
        let paused_until = self.paused_until.clone();
        let config = self.config.clone();

        thread::spawn(move || {
            let mut mouse = match HumanMouse::new() {
                Ok(m) => m,
                Err(e) => {
                    eprintln!("Failed to initialize mouse: {}", e);
                    running.store(false, Ordering::SeqCst);
                    return;
                }
            };

            let mut enigo = match Enigo::new(&Settings::default()) {
                Ok(e) => e,
                Err(e) => {
                    eprintln!("Failed to initialize keyboard: {}", e);
                    running.store(false, Ordering::SeqCst);
                    return;
                }
            };

            while running.load(Ordering::SeqCst) {
                if !config.enabled {
                    thread::sleep(Duration::from_secs(1));
                    continue;
                }

                // Check if paused
                {
                    let pause = paused_until.lock().unwrap();
                    if let Some(until) = *pause {
                        if Instant::now() < until {
                            drop(pause);
                            thread::sleep(Duration::from_secs(1));
                            continue;
                        }
                    }
                }

                // Check work hours
                if config.work_hours.enabled && !is_within_work_hours(&config) {
                    thread::sleep(Duration::from_secs(60));
                    continue;
                }

                // Calculate next interval with variance
                let interval = calculate_interval(&config);

                // Check for natural break
                let mut rng = rng();
                if config.natural_breaks.enabled && rng.gen_bool(config.natural_breaks.chance) {
                    let break_mins = rng.gen_range(
                        config.natural_breaks.duration_min..=config.natural_breaks.duration_max,
                    );
                    println!("Taking a natural break for {} minutes", break_mins);
                    thread::sleep(Duration::from_secs(break_mins as u64 * 60));
                    continue;
                }

                // Perform activity
                let result = match config.mode.as_str() {
                    "mouse" => mouse.human_move(config.human_like),
                    "keyboard" => jiggle_keyboard(&mut enigo),
                    "both" => {
                        if rng.gen_bool(0.5) {
                            mouse.human_move(config.human_like)
                        } else {
                            jiggle_keyboard(&mut enigo)
                        }
                    }
                    _ => mouse.human_move(config.human_like),
                };

                if let Err(e) = result {
                    eprintln!("Activity failed: {}", e);
                }

                // Sleep until next activity
                thread::sleep(Duration::from_millis(interval));
            }
        });
    }

    pub fn stop(&mut self) {
        self.running.store(false, Ordering::SeqCst);
    }

    pub fn pause(&mut self, minutes: u32) {
        let mut pause = self.paused_until.lock().unwrap();
        *pause = Some(Instant::now() + Duration::from_secs(minutes as u64 * 60));
    }

    pub fn resume(&mut self) {
        let mut pause = self.paused_until.lock().unwrap();
        *pause = None;
    }

    pub fn is_paused(&self) -> bool {
        let pause = self.paused_until.lock().unwrap();
        if let Some(until) = *pause {
            if Instant::now() < until {
                return true;
            }
        }
        false
    }

    pub fn pause_remaining_minutes(&self) -> Option<u32> {
        let pause = self.paused_until.lock().unwrap();
        if let Some(until) = *pause {
            let now = Instant::now();
            if now < until {
                let remaining = until.duration_since(now);
                return Some((remaining.as_secs() / 60 + 1) as u32);
            }
        }
        None
    }
}

fn calculate_interval(config: &Config) -> u64 {
    let mut rng = rng();
    let base = config.interval_base_ms as f64;
    let variance = base * config.interval_variance;
    let random_offset = rng.gen_range(-variance..variance);
    (base + random_offset).max(30_000.0) as u64 // Minimum 30 seconds
}

fn jiggle_keyboard(enigo: &mut Enigo) -> Result<(), String> {
    // Press and release Shift key (produces no visible output)
    enigo.key(Key::Shift, enigo::Direction::Press).map_err(|e| e.to_string())?;
    thread::sleep(Duration::from_millis(50));
    enigo.key(Key::Shift, enigo::Direction::Release).map_err(|e| e.to_string())?;
    Ok(())
}

fn is_within_work_hours(config: &Config) -> bool {
    use chrono::Local;

    let now = Local::now();
    let current_time = now.format("%H:%M").to_string();

    current_time >= config.work_hours.start && current_time <= config.work_hours.end
}

