pub struct WorkHours {
    pub enabled: bool,
    pub start: String,
    pub end: String,
}

impl Default for WorkHours {
    fn default() -> Self {
        Self {
            enabled: false,
            start: "09:00".to_string(),
            end: "18:00".to_string(),
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NaturalBreaks {
    pub enabled: bool,
    pub chance: f64,
    pub duration_min: u32,
    pub duration_max: u32,
}

impl Default for NaturalBreaks {
    fn default() -> Self {
        Self {
            enabled: true,
            chance: 0.05,
            duration_min: 15,
            duration_max: 30,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Config {
    pub enabled: bool,
    pub mode: String,
    pub interval_base_ms: u64,
    pub interval_variance: f64,
    pub human_like: bool,
    pub work_hours: WorkHours,
    pub natural_breaks: NaturalBreaks,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            enabled: true,
            mode: "mouse".to_string(),
            interval_base_ms: 180_000, // 3 minutes
            interval_variance: 0.5,     // ±50%
            human_like: true,
            work_hours: WorkHours::default(),
            natural_breaks: NaturalBreaks::default(),
        }
    }
}

impl Config {
    fn config_path() -> Option<PathBuf> {
        ProjectDirs::from("com", "compliance", "Compliance")
            .map(|dirs| dirs.config_dir().join("config.json"))
    }

    pub fn load() -> Self {
        if let Some(path) = Self::config_path() {
            if path.exists() {
                if let Ok(content) = fs::read_to_string(&path) {
                    if let Ok(config) = serde_json::from_str(&content) {
                        return config;
                    }
                }
            }
        }
        Self::default()
    }

    pub fn save(&self) -> Result<(), String> {
        let path = Self::config_path().ok_or("Could not determine config path")?;

        println!("[Config] Saving to: {:?}", path);

        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent).map_err(|e| {
                let err = format!("Failed to create config dir: {}", e);
                println!("[Config] {}", err);
                err
            })?;
        }

        let content = serde_json::to_string_pretty(self).map_err(|e| e.to_string())?;
        fs::write(&path, content).map_err(|e| {
            let err = format!("Failed to write config: {}", e);
            println!("[Config] {}", err);
            err
        })?;

        println!("[Config] Saved successfully");
        Ok(())
    }
}

