:root {
  --bg-primary: #1e1e1e;
  --bg-secondary: #2a2a2a;
  --bg-tertiary: #323232;
  --bg-elevated: #3a3a3a;
  --text-primary: rgba(255, 255, 255, 0.9);
  --text-secondary: #98989d;
  --text-tertiary: #636366;
  --accent: #0a84ff;
  --accent-hover: #409cff;
  --border: rgba(255, 255, 255, 0.01);
  --success: #30d158;
  --radius: 10px;
  --radius-sm: 6px;
  --shadow: 0 1px 3px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 4px 12px rgba(0, 0, 0, 0.3);
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  background: transparent;
}

html, body {
  overflow-x: hidden;
  overscroll-behavior-x: none;
}

body {
  font-family: "SF Pro", BlinkMacSystemFont, 'SF Pro Text', 'Segoe UI', Roboto, sans-serif;
  background: var(--bg-primary);
  color: var(--text-primary);
  min-height: 100vh;
  line-height: 1.4;
  font-size: 13px;
  -webkit-font-smoothing: antialiased;
  border-radius: 10px;
  overflow: hidden;
}

.container {
  margin: 0 auto;
  padding: 3.8rem 1.35rem 1rem;
}
